<script>
 import{Code2,Play,FileCode}from'lucide-svelte';let question=$state(''),files=$state('src/routes/+page.svelte\npackage.json'),answer=$state(''),error=$state(''),running=$state(false);
 async function analyze(){running=true;error='';answer='';const r=await fetch('/api/intelligence/coding',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({question,files:files.split('\n').map(file=>file.trim()).filter(Boolean)})});const d=await r.json();if(!r.ok)error=`${d.error}. Start Ollama or configure an allowed provider.`;else answer=d.content;running=false}
</script>
<svelte:head><title>Coding · J.A.R.V.I.S.</title></svelte:head><div class="page"><header><Code2 size={22}/><div><h1>Repository Coding Assistant</h1><p>Model-assisted analysis limited to the files you explicitly select.</p></div></header><section class="workspace"><div class="inputs"><label>Question<textarea bind:value={question} placeholder="Explain this architecture, diagnose a bug, or propose a refactor"></textarea></label><label><FileCode size={14}/>Repository files (one per line)<textarea class="files" bind:value={files} spellcheck="false"></textarea></label><button onclick={analyze} disabled={running||!question.trim()}><Play size={14}/>{running?'Analyzing…':'Analyze repository context'}</button></div><article aria-live="polite">{#if error}<p class="error">{error}</p>{:else if answer}<pre>{answer}</pre>{:else}<p>Analysis will appear here. No files are modified by this assistant.</p>{/if}</article></section></div>
<style>.page{padding:var(--space-6);display:grid;gap:var(--space-5)}header{display:flex;align-items:center;gap:.8rem}h1{margin:0;font-size:var(--text-2xl)}header p,article p{margin:.25rem 0;color:var(--text-secondary);font-size:var(--text-sm)}.workspace{display:grid;grid-template-columns:minmax(280px,.8fr) minmax(320px,1.2fr);gap:.8rem}.inputs,article{border:1px solid var(--surface-border);background:var(--surface-card);border-radius:var(--radius-lg);padding:1rem}.inputs{display:grid;gap:.8rem;align-content:start}label{display:grid;gap:.4rem;font-size:var(--text-xs);color:var(--text-secondary)}textarea,button{border:1px solid var(--surface-border);background:var(--surface-bg);color:var(--text-primary);border-radius:var(--radius-md);padding:.7rem}textarea{min-height:130px}.files{min-height:100px;font-family:var(--font-mono)}button{display:flex;justify-content:center;align-items:center;gap:.4rem;background:var(--color-neutral-900);color:white;cursor:pointer}pre{white-space:pre-wrap;word-break:break-word;font:inherit;font-size:var(--text-sm);line-height:1.65;margin:0}.error{color:var(--color-error-500)}@media(max-width:750px){.page{padding:var(--space-4)}.workspace{grid-template-columns:1fr}}</style>
